#include<cstdio>
#include<vector>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;
const int N=1.2e6;int fa[N],n,siz[N],cnt[N];vector<int> D;
int cc;inline void work()
{
	memset(siz,0,sizeof(siz));memset(cnt,0,sizeof(cnt));
	drep(n,2,i)siz[fa[i]]+=(++siz[i]);++siz[1];
	rep(1,n,i)++cnt[siz[i]];
	printf("Case #%d:\n1\n",++cc);
	for(int i:D)
	{
		ll tmp=0;for(int j=i;j<=n;j+=i)tmp+=cnt[j];
		if(tmp*i>=n)printf("%d\n",i);
	}
}
int main()
{
	n=read();rep(2,n,i)fa[i]=read();
	rep(2,n,i)if(n%i==0)D.push_back(i);work();
	int T=9;while(T--){rep(2,n,i)fa[i]=(fa[i]+19940105)%(i-1)+1;work();}return 0;
}
